{"content":"12227: void nsHttpChannel::MaybeRaceCacheWithNetwork() {
12228:   nsresult rv;
12229: 
12230:   nsCOMPtr<nsINetworkLinkService> netLinkSvc;
12231:   netLinkSvc = do_GetService(NS_NETWORK_LINK_SERVICE_CONTRACTID, &rv);
12232:   if (NS_FAILED(rv)) {
12233:     return;
12234:   }
12235: 
12236:   uint32_t linkType;
12237:   rv = netLinkSvc->GetLinkType(&linkType);
12238:   if (NS_FAILED(rv)) {
12239:     return;
12240:   }
12241: 
12242:   if (!(linkType == nsINetworkLinkService::LINK_TYPE_ETHERNET ||
12243: #ifndef MOZ_WIDGET_ANDROID
12244:         // On Android we don't assume an unknown link type is unmetered
12245:         linkType == nsINetworkLinkService::LINK_TYPE_UNKNOWN ||
12246: #endif
12247:         linkType == nsINetworkLinkService::LINK_TYPE_USB ||
12248:         linkType == nsINetworkLinkService::LINK_TYPE_WIFI)) {
12249:     return;
12250:   }
12251: 
12252:   // Don't trigger the network if the load flags say so.
12253:   if (mLoadFlags & (LOAD_ONLY_FROM_CACHE | LOAD_NO_NETWORK_IO)) {
12254:     return;
12255:   }
12256: 
12257:   // We must not race if the channel has a failure status code.
12258:   if (NS_FAILED(mStatus)) {
12259:     return;
12260:   }
12261: 
12262:   // If a CORS Preflight is required we must not race.
12263:   if (LoadRequireCORSPreflight() && !LoadIsCorsPreflightDone()) {
12264:     return;
12265:   }
12266: 
12267:   if (CacheFileUtils::CachePerfStats::IsCacheSlow()) {
12268:     // If the cache is slow, trigger the network request immediately.
12269:     mRaceDelay = 0;
12270:   } else {
12271:     // Give cache a headstart of 3 times the average cache entry open time.
12272:     mRaceDelay = CacheFileUtils::CachePerfStats::GetAverage(
12273:                      CacheFileUtils::CachePerfStats::ENTRY_OPEN, true) *
12274:                  3;
12275:     // We use microseconds in CachePerfStats but we need milliseconds
12276:     // for TriggerNetwork.
12277:     mRaceDelay /= 1000;
12278:   }
12279: 
12280:   mRaceDelay = std::clamp<uint32_t>(
12281:       mRaceDelay, StaticPrefs::network_http_rcwn_min_wait_before_racing_ms(),
12282:       StaticPrefs::network_http_rcwn_max_wait_before_racing_ms());
12283: 
12284:   MOZ_ASSERT(StaticPrefs::network_http_rcwn_enabled() || mNetworkTriggerDelay,
12285:              "The pref must be turned on.");
12286:   LOG(("nsHttpChannel::MaybeRaceCacheWithNetwork [this=%p, delay=%u]\n", this,
12287:        mRaceDelay));
12288: 
12289:   TriggerNetworkWithDelay(mRaceDelay);
12290: }
